import { VexClient } from '@vex-sdk/client';
import { AzureAgentClient } from '@azure/ai-projects';

// npm install @vex-sdk/client @azure/ai-projects
const vex = new VexClient({ apiKey: 'your-vex-key' });
const agent = new AzureAgentClient({ projectId: 'your-project-id' });

async function sendCompliantNotification(candidateEmail: string, decision: string) {
    const agentDecision = await agent.invoke('generate_rejection', { email: candidateEmail });

    // Vex injects NYC Local Law 144 disclosure
    const compliantEmail = await vex.enrich(
        agentDecision,
        {
            policy: 'nyc_ll144',
            required: ['ai_disclosure_notice'],
            context: { decision, candidateEmail }
        }
    );

    if (!compliantEmail.valid) {
        throw new Error(`Compliance failure: ${compliantEmail.violations.join(', ')}`);
    }

    return await sendEmail(compliantEmail.content);
}

from vex_sdk import VexAudit
from azure.ai.projects import AgentSession

import json

class HRAuditLogger:
    def __init__(self):
        self.audit = VexAudit(api_key="your-vex-key", dataset="hr-screening-audit-2024")

    def log_screening_decision(self, session: AgentSession, input_resumes: list, output_rankings: dict):
        audit_record = {
            "timestamp": "2024-01-15T10:30:00Z",
            "agent_thread": session.thread_id,
            "input_count": len(input_resumes),
            "protected_attributes_detected": self._extract_protected_attrs(input_resumes),
            "ranking_changes": output_rankings,
            "bias_score": self.audit.calculate_bias_score(output_rankings)
        }

        self.audit.log(audit_record)

        if audit_record["bias_score"] > 0.3:
            self.audit.flag_high_risk(audit_record)

    def _extract_protected_attrs(self, resumes):
        return self.audit.scan_protected_attributes(resumes)
